<section class="content">
  <table class="table table-p-0">
<thead>
  {% set company_doc = frappe.get_doc("Company", doc.company) %}

  {# Company Master se linked Address nikaalne ka sahi logic #}
  {# Hum pehle wo Address dhund rahe hain jo 'Company' se linked ho aur 'is_your_company_address' marked ho #}
  {% set address_list = frappe.get_list("Address", 
      filters=[
          ["Dynamic Link", "link_doctype", "=", "Company"],
          ["Dynamic Link", "link_name", "=", doc.company],
          ["is_your_company_address", "=", 1]
      ], 
      fields=["name"], limit=1) 
  %}

  {% set addr = None %}
  {% if address_list %}
      {% set addr = frappe.get_doc("Address", address_list[0].name) %}
  {% endif %}

  <tr>
    <td colspan="10">
      <div class="table-content mb-0 pb-1">
        <div class="row">
          <div class="col-100">
            <div class="sb-header border-top border-default">
              <div class="header-content">
                <div class="table-content">
                  <div class="row">

                    <!-- Logo -->
                    <div class="col-50">
                      <img src="{{ company_doc.logo_for_printing or company_doc.company_logo or '' }}" 
                           class="header-logo" 
                           style="max-height:75px;">
                    </div>

                    <!-- Company Details -->
                    <div class="col-50">
                      <table class="table border-none-all table-p-1">
                        <tbody>

                          <!-- Company Name -->
                          <tr>
                            <td colspan="2">
                              <p class="fs-small fw-bolder fst-upper">
                                {{ company_doc.company_name }}
                              </p>
                            </td>
                          </tr>

                          <!-- GST -->
                          <tr>
                            <td style="width:60px;">
                              <p class="fs-small text-muted fw-bold">GSTIN:</p>
                            </td>
                            <td>
                              <p class="fs-small text-muted fw-bold">
                                {{ company_doc.gstin or "-" }}
                              </p>
                            </td>
                          </tr>

                          <!-- PAN -->
                          <tr>
                            <td>
                              <p class="fs-small text-muted fw-bold">PAN:</p>
                            </td>
                            <td>
                              <p class="fs-small text-muted fw-bold">
                                {{ company_doc.pan or "-" }}
                              </p>
                            </td>
                          </tr>

                          <!-- Company Address -->
                          <tr>
                            <td style="vertical-align:top;">
                              <p class="fs-small text-muted">Address:</p>
                            </td>
                            <td>
                              <div class="fs-small text-muted">
                                {% if addr %}
                                  {{ addr.address_line1 or "" }}
                                  {% if addr.address_line2 %}, {{ addr.address_line2 }}{% endif %}
                                  <br>
                                  {{ addr.city or "" }}{% if addr.state %}, {{ addr.state }}{% endif %}
                                  <!--{% if addr.pincode %} - {{ addr.pincode }}{% endif %}-->
                                  <br>
                                  <!--{{ addr.country or "" }}-->
                                {% else %}
                                  {# Fallback: agar koi link nahi mila toh company ki default display field use karein #}
                                  {{ company_doc.address_display or "Address not set" }}
                                {% endif %}
                              </div>
                            </td>
                          </tr>

                        </tbody>
                      </table>

                      <!-- Contact Info -->
                      <div class="d-flex" style="gap:60px; margin-top:5px;">
                        <span class="d-inline-flex align-items-center">
                          <span style="color:#230bb3; font-size:18px;">&#9990;</span>
                          <p class="d-inline fs-mini text-muted font_no ps-1">
                            {{ company_doc.phone_no or "" }}
                          </p>
                        </span>

                        <span class="d-inline-flex align-items-center">
                          <span style="color:#230bb3; font-size:18px;">&#9993;</span>
                          <p class="d-inline fs-mini text-muted font_no ps-1">
                            {{ company_doc.email or "" }}
                          </p>
                        </span>
                      </div>

                    </div>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </td>
  </tr>
</thead>
    <tbody>
