            </thead>
            <tbody>
              {%- for item in doc.items -%}
              <code class="d-none">
                {% set cgst_amt = [] -%}
                {% set sgst_amt = [] -%}
                {% set igst_amt = [] -%}
                {% set it_cgst_rate = [] -%}
                {% set it_sgst_rate = [] -%}
                {% set it_igst_rate = [] -%}
                {% set rate_found_item = 0 -%}
                {%- set item_record = frappe.get_doc("Item", item.item_code) -%}
                {% set mydict = json.loads(item.item_tax_rate) %}

                <!--new logic item wise tax-->
                {% for item_tax in item_record.taxes %}
                {% if item_tax.item_tax_template == igst_account_head[0] %}
                {% set _ = it_igst_rate.append(item_tax.tax_category) %}
                {% set _ = igst_amt.append(item.amount * it_igst_rate[0] / 100) -%}
                {% set rate_found_item = 1 -%}
                {% endif %}

                {% if item_tax.item_tax_template == sgst_account_head[0] %}
                {% set _ = it_sgst_rate.append(item_tax.tax_category) %}
                {% set _ = sgst_amt.append(item.amount * it_sgst_rate[0] / 100) -%}
                {% set rate_found_item = 1 -%}
                {% endif %}

                {% if item_tax.item_tax_template == cgst_account_head[0] %}
                {% set _ = it_cgst_rate.append(item_tax.tax_category) %}
                {% set _ = cgst_amt.append(item.amount * it_cgst_rate[0] / 100) -%}
                {% set rate_found_item = 1 -%}
                {% endif %}

                {% endfor %}
                {% if rate_found_item == 0 %}
                {% if cgst_rate[0] -%}
                {% set _ = cgst_amt.append((item.amount * cgst_rate[0])/100) -%}
                {% set _= it_cgst_rate.append(cgst_rate[0]) -%}
                {% set rate_found_inv = 1 -%}
                {%- endif -%}
                {% if sgst_rate[0] -%}
                {% set _ = sgst_amt.append((item.amount * sgst_rate[0])/100) -%}
                {% set _= it_sgst_rate.append(sgst_rate[0]) -%}
                {%- endif -%}
                {% if igst_rate[0] -%}
                {% set _ = igst_amt.append((item.amount * igst_rate[0])/100) -%}
                {% set _= it_igst_rate.append(igst_rate[0]) -%}
                {% set rate_found_inv = 1 -%}
                {%- endif -%}
                {% endif %}

                <!--Start new logic item wise tax-->
                {% if not it_cgst_rate[0] %}
                {% for key, value in mydict.items() %}
                {% if cgst_account_head[0] == key %}
                {% set _ = it_cgst_rate.append(value) %}
                {% for item_tax in doc.taxes %}
                {% if item_tax.account_head == key %}
                {% if item_tax.included_in_print_rate == 1 %}
                {% set _ = cgst_amt.append(((item.net_rate * item.qty) * it_cgst_rate[0])/100) -%}
                {% else %}

                {% set _ = cgst_amt.append(((item.net_rate * item.qty) * it_cgst_rate[0])/100) -%}
                {% endif %}
                {% endif %}
                {% endfor %}

                {% set _ = cgst_amt.append(((item.net_rate * item.qty) * it_cgst_rate[0])/100) -%}
                {% endif %}
                {% endfor %}
                {% endif %}
                {% if not it_sgst_rate[0] %}
                {% for key, value in mydict.items() %}
                {% if sgst_account_head[0] == key %}
                {% set _ = it_sgst_rate.append(value) %}
                {% for item_tax in doc.taxes %}
                {% if item_tax.account_head == key %}
                {% if item_tax.included_in_print_rate == 1 %}
                {% set _ = sgst_amt.append(((item.net_rate * item.qty) * it_sgst_rate[0])/100) -%}
                {% else %}
                {% set _ = sgst_amt.append(((item.net_rate * item.qty) * it_sgst_rate[0])/100) -%}
                {% endif %}
                {% endif %}
                {% endfor %}
                {% set _ = sgst_amt.append(((item.net_rate * item.qty) * it_sgst_rate[0])/100) -%}
                {% endif %}
                {% endfor %}
                {% endif %}
                {% if not it_igst_rate[0] %}
                {% for key, value in mydict.items() %}
                {% if igst_account_head[0] == key %}
                {% set _ = it_igst_rate.append(value) %}
                {% for item_tax in doc.taxes %}
                {% if item_tax.account_head == key %}
                {% if item_tax.included_in_print_rate == 1 %}
                {% set _ = igst_amt.append(((item.net_rate * item.qty) * it_igst_rate[0])/100) -%}
                {% else %}
                {% set _ = igst_amt.append(((item.net_rate * item.qty) * it_igst_rate[0])/100) -%}
                {% endif %}
                {% endif %}
                {% endfor %}
                {% set _ = igst_amt.append(((item.net_rate * item.qty) * it_igst_rate[0])/100) -%}
                {% set _ = igst_amt.append(((item.net_rate * item.qty) * (it_igst_rate[0]/100))) -%}
                {% endif %}
                {% endfor %}
                {% endif %}

                <!--End new logic item wise tax-->
                {% if not it_cgst_rate[0] %}
                {% set _ = it_cgst_rate.append(0) %}
                {% set _ = cgst_amt.append(0) %}
                {% endif %}
                {% if not it_sgst_rate[0] %}
                {% set _ = it_sgst_rate.append(0) %}
                {% set _ = sgst_amt.append(0) %}
                {% endif %}
                {% if not it_igst_rate[0] %}
                {% set _ = it_igst_rate.append(0) %}
                {% set _ = igst_amt.append(0) %}
                {% endif %}

                {% set custom_tax_rate = it_cgst_rate[0] + it_sgst_rate[0] + it_igst_rate[0] %}
                {% if item.gst_hsn_code|string in items_dict %}
                {% if custom_tax_rate|string in items_dict.get(item.gst_hsn_code) %}
                {% set _ = items_dict[''+item.gst_hsn_code|string].update( {
                ''+custom_tax_rate|string : {
                'qty': items_dict.get(item.gst_hsn_code).get(custom_tax_rate|string).get('qty') | int + item.qty |
                int ,
                'taxable_amount':
                items_dict.get(item.gst_hsn_code).get(custom_tax_rate|string).get('taxable_amount') | float +
                item.base_net_amount,
                'tax_rate': items_dict.get(item.gst_hsn_code).get(custom_tax_rate|string).get('tax_rate') | int +
                custom_tax_rate,
                'cgst_rate': items_dict.get(item.gst_hsn_code).get(custom_tax_rate|string).get('cgst_rate') |int
                | float + it_cgst_rate[0],
                'cgst_amt': items_dict.get(item.gst_hsn_code).get(custom_tax_rate|string).get('cgst_amt') | float + cgst_amt[0],
                'sgst_rate': items_dict.get(item.gst_hsn_code).get(custom_tax_rate|string).get('sgst_rate') |int
                | float + it_sgst_rate[0],
                'sgst_amt': items_dict.get(item.gst_hsn_code).get(custom_tax_rate|string).get('sgst_amt')
                | float + sgst_amt[0],
                'igst_rate': items_dict.get(item.gst_hsn_code).get(custom_tax_rate|string).get('igst_rate') |int
                | float + it_igst_rate[0],
                'igst_amt': items_dict.get(item.gst_hsn_code).get(custom_tax_rate|string).get('igst_amt')
                | float + igst_amt[0] ,
                'loop': items_dict.get(item.gst_hsn_code).get(custom_tax_rate|string).get('loop') | float
                + 1 ,
                'total_tax': items_dict.get(item.gst_hsn_code).get(custom_tax_rate|string).get('total_tax')
               |float + (cgst_amt[0] + sgst_amt[0] + igst_amt[0])
                } }) %}
                {% else %}
                {% set _ = items_dict[''+item.gst_hsn_code|string].update({''+custom_tax_rate|string : {'qty':
                item.qty ,
                'taxable_amount': item.base_net_amount, 'tax_rate': custom_tax_rate, 'cgst_rate':
                it_cgst_rate[0], 'cgst_amt': cgst_amt[0],
                'sgst_rate': it_sgst_rate[0], 'sgst_amt': sgst_amt[0], 'igst_rate': it_igst_rate[0], 'igst_amt':
                igst_amt[0], 'loop':1.0, 'total_tax': cgst_amt[0] + sgst_amt[0] + igst_amt[0] }
                }) %}
                {% endif %}
                {% else %}
                {% set _ = items_dict.update({''+item.gst_hsn_code|string : {''+custom_tax_rate|string: { 'qty':
                item.qty ,
                'taxable_amount': item.base_net_amount, 'tax_rate': custom_tax_rate, 'cgst_rate':
                it_cgst_rate[0], 'cgst_amt': cgst_amt[0],
                'sgst_rate': it_sgst_rate[0], 'sgst_amt': sgst_amt[0], 'igst_rate': it_igst_rate[0], 'igst_amt':
                igst_amt[0],'loop':1.0, 'total_tax': cgst_amt[0] + sgst_amt[0] + igst_amt[0] } }}) %}
                {% endif %}
                {% set total_tax = cgst_amt[0] + sgst_amt[0] + igst_amt[0] %}
                {%- set total_tax_rate = it_cgst_rate[0] + it_sgst_rate[0] + it_igst_rate[0] -%}
                {%- set _ = extra_data.update({"taxable_amt":(item.get("rate", 0)/(1+total_tax_rate/100)) + extra_data.get("taxable_amt", 0) }) -%}

                {%- set _ = extra_data.update({'is_igst':igst_amt[0] > 0}) -%}

                {%- for voucher_calc in doc.get("custom_voucher_calculation_for_gift", []) -%}
                  {%- if voucher_calc.get("product_upc") == item.get("item_code") -%}
                    {%- set _ = gift_voucher_calc.update({item.get("item_code"):voucher_calc}) -%}
                    {%- set _ = extra_data.update({"voucher_calc":voucher_calc}) -%}
                  {%- endif -%}
                {%- endfor -%}

                {%- set voucher_calc = extra_data.get("voucher_calc") -%}
              </code>
              <tr>
                <td>
                  <p class="fs-mini">
                    {{loop.index}}.
                  </p>
                </td>
                <td>
                  <div class="fs-mini">
                    {{item.description|striptags}}
                  </div>
                </td>
                <td>
                  <p class="fs-mini">
                    {{item.get_formatted("gst_hsn_code")}}
                  </p>
                </td>

                <!-- Unit Price -->
                {%- set item_price = (item.get("rate", 0)/(1+total_tax_rate/100)) -%}
                <td>
                  <p class="fs-mini">
                    {{frappe.utils.fmt_money(item_price, currency=doc.currency, precision=2)}}

                    {%- set _ = total_data.update({'price':item_price + total_data.get("price", 0)}) -%}
                  </p>
                </td>
                <td>
                  <p class="fs-mini">
                    {%- set item_qty = item.get("qty") -%}
                    {{item_qty}}
                    {%- set _ = total_data.update({'qty':item_qty + total_data.get("qty", 0)}) -%}
                  </p>
                </td>
                <!-- Basic Amt -->
                <td>
                  <p class="fs-mini">
                    {%- set basic_amt = voucher_calc.get("taxable_amount")|float -%}

                    {{frappe.utils.fmt_money(basic_amt, currency=doc.currency, precision=2)}}
                    {%- set _ = total_data.update({'basic_amt':basic_amt + total_data.get("basic_amt",
                    0)}) -%}
                  </p>
                </td>
                <!-- Discount Price -->
                <td>
                  <p class="fs-mini">
                    {%- set item_price = voucher_calc.get("taxable_amount")|float -%}

                    {%- set discount_price = (item.get("rate", 0)/(1+total_tax_rate/100)) -
                    item_price -%}

                    {{frappe.utils.fmt_money(discount_price, currency=doc.currency, precision=2)}}
                    {%- set _ = total_data.update({'discount_price':discount_price + total_data.get("discount_price",
                    0)}) -%}
                  </p>
                </td>

                <!-- Taxable Amount -->
                <td>
                  <p class="fs-mini">
                    {%- set item_qty = item.get('qty', 0) -%}
                    {%- set item_rate = item.get('rate', 0) -%}
                    {%- set item_taxable_amt = item_rate - item_price -%}
                    {%- set item_taxable_amt = item_price * item_qty -%}


                    {{frappe.utils.fmt_money(item_taxable_amt, currency=doc.currency, precision=2)}}

                    {%- set _ = total_data.update({'taxable_amt':item_taxable_amt + total_data.get("taxable_amt", 0)})
                    -%}
                  </p>
                </td>

                <!-- Tax fields start -->
                <td>
                  <p class="fs-mini">
                    {% if it_igst_rate[0] > 0 %}
                    {{it_igst_rate[0]}}
                    {%- set _ = total_data.update({"igst_rate":it_igst_rate[0] + total_data.get("igst_rate")}) -%}
                    {% else %}
                    N/A
                    {% endif %}
                  </p>
                </td>
                <td>
                  <p class="fs-mini">
                    {% if it_igst_rate[0] > 0 %}
                    <!-- {{frappe.utils.fmt_money(igst_amt[0], currency=doc.currency, precision=2)}} -->
                    {%- set igst_amt = voucher_calc.get("gst_value")|float * voucher_calc.get("qty")|float-%}
                    {{igst_amt}}
                    {%- set _ = total_data.update({"igst_amt":igst_amt + total_data.get("igst_amt")}) -%}
                    {%- set _ = total_data.update({"total_tax": igst_amt + total_data.get("total_tax", 0)}) -%}
                    {% else %}
                    N/A
                    {% endif %}
                  </p>
                </td>
                <td>
                  <p class="fs-mini">
                    {% if it_sgst_rate[0] > 0 %}
                    {{it_sgst_rate[0]}}
                    {%- set _ = total_data.update({"sgst_rate":it_sgst_rate[0] + total_data.get("sgst_rate")}) -%}
                    {%- else -%}
                    N/A
                    {%- endif -%}
                  </p>
                </td>
                <td>
                  <p class="fs-mini">
                    {% if it_sgst_rate[0] > 0 %}
                    <!-- {{frappe.utils.fmt_money(sgst_amt[0], currency=doc.currency, precision=2)}} -->
                    {%- set sgst_amt = (voucher_calc.get("gst_value")|float * voucher_calc.get("qty")|float)/2 -%}
                    {{"%.2f" % sgst_amt}}
                    {%- set _ = total_data.update({"sgst_amt":sgst_amt + total_data.get("sgst_amt")}) -%}
                    {%- set _ = total_data.update({"total_tax": sgst_amt + total_data.get("total_tax", 0)}) -%}
                    {%- else -%}
                    N/A
                    {%- endif -%}
                  </p>
                </td>
                <td>
                  <p class="fs-mini">
                    {% if it_cgst_rate[0] > 0 %}
                    {{it_cgst_rate[0]}}
                    {%- set _ = total_data.update({"cgst_rate":it_cgst_rate[0] + total_data.get("cgst_rate")}) -%}
                    {%- else -%}
                    N/A
                    {%- endif -%}
                  </p>
                </td>
                <td>
                  <p class="fs-mini">
                    {% if it_cgst_rate[0] > 0 %}
                    <!-- {{frappe.utils.fmt_money(cgst_amt[0], currency=doc.currency, precision=2)}} -->
                    {%- set cgst_amt = (voucher_calc.get("gst_value")|float * voucher_calc.get("qty")|float)/2 -%}
                    {{"%.2f" % cgst_amt}}
                    {%- set _ = total_data.update({"cgst_amt":cgst_amt + total_data.get("cgst_amt")}) -%}
                    {%- set _ = total_data.update({"total_tax": cgst_amt + total_data.get("total_tax", 0)}) -%}
                    {%- else -%}
                    N/A
                    {%- endif -%}
                  </p>
                </td>
                <!-- Tax fields end -->

                <td>
                  {%- if voucher_calc -%}
                  {%- set total_amt = voucher_calc.get("order_value")|float -%}
                  {%- else -%}
                  <!-- {%- set total_amt = item.amount + total_tax -%} -->
                  {%- set total_amt = item.amount -%}
                  {%- endif -%}
                  <p class="fs-mini text-right">
                    {{frappe.utils.fmt_money(total_amt, currency=doc.currency, precision=2)}}
                    {%- set _ = total_data.update({'total_amt':total_amt + total_data.get("total_amt", 0)}) -%}
                  </p>
                </td>
              </tr>
              {%- endfor -%}

              <!-- Total Row Start -->
              <tr>
                <td colspan="5" class="">
                  <p class="fs-mini text-end fw-bold">
                    Total
                  </p>
                </td>
                <!-- Basic amt total -->
                <td>
                  <p class="fs-mini">
                    {{frappe.utils.fmt_money(total_data.get("basic_amt"), currency=doc.currency, precision=2)}}
                  </p>
