            <tbody>
              {%- for item in doc.items -%}
              <code class="d-none">
                {% set cgst_amt = [] -%}
                {% set sgst_amt = [] -%}
                {% set igst_amt = [] -%}
                {% set it_cgst_rate = [] -%}
                {% set it_sgst_rate = [] -%}
                {% set it_igst_rate = [] -%}
                {% set rate_found_item = 0 -%}
                {%- set item_record = frappe.get_doc("Item", item.item_code) -%}
                {% set mydict = json.loads(item.item_tax_rate) %}

                <!--new logic item wise tax-->
                {% for item_tax in item_record.taxes %}
                {% if item_tax.item_tax_template == igst_account_head[0] %}
                {% set _ = it_igst_rate.append(item_tax.tax_category) %}
                {% set _ = igst_amt.append(item.amount * it_igst_rate[0] / 100) -%}
                {% set rate_found_item = 1 -%}
                {% endif %}

                {% if item_tax.item_tax_template == sgst_account_head[0] %}
                {% set _ = it_sgst_rate.append(item_tax.tax_category) %}
                {% set _ = sgst_amt.append(item.amount * it_sgst_rate[0] / 100) -%}
                {% set rate_found_item = 1 -%}
                {% endif %}

                {% if item_tax.item_tax_template == cgst_account_head[0] %}
                {% set _ = it_cgst_rate.append(item_tax.tax_category) %}
                {% set _ = cgst_amt.append(item.amount * it_cgst_rate[0] / 100) -%}
                {% set rate_found_item = 1 -%}
                {% endif %}

                {% endfor %}
                {% if rate_found_item == 0 %}
                {% if cgst_rate[0] -%}
                {% set _ = cgst_amt.append((item.amount * cgst_rate[0])/100) -%}
                {% set _= it_cgst_rate.append(cgst_rate[0]) -%}
                {% set rate_found_inv = 1 -%}
                {%- endif -%}
                {% if sgst_rate[0] -%}
                {% set _ = sgst_amt.append((item.amount * sgst_rate[0])/100) -%}
                {% set _= it_sgst_rate.append(sgst_rate[0]) -%}
                {%- endif -%}
                {% if igst_rate[0] -%}
                {% set _ = igst_amt.append((item.amount * igst_rate[0])/100) -%}
                {% set _= it_igst_rate.append(igst_rate[0]) -%}
                {% set rate_found_inv = 1 -%}
                {%- endif -%}
                {% endif %}

                <!--Start new logic item wise tax-->
                {% if not it_cgst_rate[0] %}
                {% for key, value in mydict.items() %}
                {% if cgst_account_head[0] == key %}
                {% set _ = it_cgst_rate.append(value) %}
                {% for item_tax in doc.taxes %}
                {% if item_tax.account_head == key %}
                {% if item_tax.included_in_print_rate == 1 %}
                {% set _ = cgst_amt.append(((item.net_rate * item.qty) * it_cgst_rate[0])/100) -%}
                {% else %}

                {% set _ = cgst_amt.append(((item.net_rate * item.qty) * it_cgst_rate[0])/100) -%}
                {% endif %}
                {% endif %}
                {% endfor %}

                {% set _ = cgst_amt.append(((item.net_rate * item.qty) * it_cgst_rate[0])/100) -%}
                {% endif %}
                {% endfor %}
                {% endif %}
                {% if not it_sgst_rate[0] %}
                {% for key, value in mydict.items() %}
                {% if sgst_account_head[0] == key %}
                {% set _ = it_sgst_rate.append(value) %}
                {% for item_tax in doc.taxes %}
                {% if item_tax.account_head == key %}
                {% if item_tax.included_in_print_rate == 1 %}
                {% set _ = sgst_amt.append(((item.net_rate * item.qty) * it_sgst_rate[0])/100) -%}
                {% else %}
                {% set _ = sgst_amt.append(((item.net_rate * item.qty) * it_sgst_rate[0])/100) -%}
                {% endif %}
                {% endif %}
                {% endfor %}
                {% set _ = sgst_amt.append(((item.net_rate * item.qty) * it_sgst_rate[0])/100) -%}
                {% endif %}
                {% endfor %}
                {% endif %}
                {% if not it_igst_rate[0] %}
                {% for key, value in mydict.items() %}
                {% if igst_account_head[0] == key %}
                {% set _ = it_igst_rate.append(value) %}
                {% for item_tax in doc.taxes %}
                {% if item_tax.account_head == key %}
                {% if item_tax.included_in_print_rate == 1 %}
                {% set _ = igst_amt.append(((item.net_rate * item.qty) * it_igst_rate[0])/100) -%}
                {% else %}
                {% set _ = igst_amt.append(((item.net_rate * item.qty) * it_igst_rate[0])/100) -%}
                {% endif %}
                {% endif %}
                {% endfor %}
                {% set _ = igst_amt.append(((item.net_rate * item.qty) * it_igst_rate[0])/100) -%}
                {% set _ = igst_amt.append(((item.net_rate * item.qty) * (it_igst_rate[0]/100))) -%}
                {% endif %}
                {% endfor %}
                {% endif %}

