                {% set _ = it_cgst_rate.append(0) %}
                {% set _ = cgst_amt.append(0) %}
                {% endif %}
                {% if not it_sgst_rate[0] %}
                {% set _ = it_sgst_rate.append(0) %}
                {% set _ = sgst_amt.append(0) %}
                {% endif %}
