                {% set _ = it_igst_rate.append(0) %}
                {% set _ = igst_amt.append(0) %}
                {% endif %}

                {% set custom_tax_rate = it_cgst_rate[0] + it_sgst_rate[0] + it_igst_rate[0] %}
                {% if item.gst_hsn_code|string in items_dict %}
                {% if custom_tax_rate|string in items_dict.get(item.gst_hsn_code) %}
                {% set _ = items_dict[''+item.gst_hsn_code|string].update( {
                ''+custom_tax_rate|string : {
                'qty': items_dict.get(item.gst_hsn_code).get(custom_tax_rate|string).get('qty') | int + item.qty |
                int ,
                'taxable_amount':
                items_dict.get(item.gst_hsn_code).get(custom_tax_rate|string).get('taxable_amount') | float +
                item.base_net_amount,
                'tax_rate': items_dict.get(item.gst_hsn_code).get(custom_tax_rate|string).get('tax_rate') | int +
                custom_tax_rate,
                'cgst_rate': items_dict.get(item.gst_hsn_code).get(custom_tax_rate|string).get('cgst_rate') |int
                | float + it_cgst_rate[0],
                'cgst_amt': items_dict.get(item.gst_hsn_code).get(custom_tax_rate|string).get('cgst_amt') 
                | float + cgst_amt[0],
                'sgst_rate': items_dict.get(item.gst_hsn_code).get(custom_tax_rate|string).get('sgst_rate') |int
                | float + it_sgst_rate[0],
                'sgst_amt': items_dict.get(item.gst_hsn_code).get(custom_tax_rate|string).get('sgst_amt')
                | float + sgst_amt[0],
                'igst_rate': items_dict.get(item.gst_hsn_code).get(custom_tax_rate|string).get('igst_rate') |int
                | float + it_igst_rate[0],
                'igst_amt': items_dict.get(item.gst_hsn_code).get(custom_tax_rate|string).get('igst_amt')
                | float + igst_amt[0] ,
                'loop': items_dict.get(item.gst_hsn_code).get(custom_tax_rate|string).get('loop') | float
                + 1 ,
                'total_tax': items_dict.get(item.gst_hsn_code).get(custom_tax_rate|string).get('total_tax')
                |float + (cgst_amt[0] + sgst_amt[0] + igst_amt[0])
                } }) %}
                {% else %}
                {% set _ = items_dict[''+item.gst_hsn_code|string].update({''+custom_tax_rate|string : {'qty':
                item.qty ,
                'taxable_amount': item.base_net_amount, 'tax_rate': custom_tax_rate, 'cgst_rate':
                it_cgst_rate[0], 'cgst_amt': cgst_amt[0],
                'sgst_rate': it_sgst_rate[0], 'sgst_amt': sgst_amt[0], 'igst_rate': it_igst_rate[0], 'igst_amt':
                igst_amt[0], 'loop':1.0, 'total_tax': cgst_amt[0] + sgst_amt[0] + igst_amt[0] }
                }) %}
                {% endif %}
                {% else %}
                {% set _ = items_dict.update({''+item.gst_hsn_code|string : {''+custom_tax_rate|string: { 'qty':
                item.qty ,
                'taxable_amount': item.base_net_amount, 'tax_rate': custom_tax_rate, 'cgst_rate':
                it_cgst_rate[0], 'cgst_amt': cgst_amt[0],
                'sgst_rate': it_sgst_rate[0], 'sgst_amt': sgst_amt[0], 'igst_rate': it_igst_rate[0], 'igst_amt':
                igst_amt[0],'loop':1.0, 'total_tax': cgst_amt[0] + sgst_amt[0] + igst_amt[0] } }}) %}
                {% endif %}
                {% set total_tax = cgst_amt[0] + sgst_amt[0] + igst_amt[0] %}
                {%- set total_tax_rate = it_cgst_rate[0] + it_sgst_rate[0] + it_igst_rate[0] -%}
                {%- set _ = extra_data.update({"taxable_amt":(item.get("rate", 0)/(1+total_tax_rate/100)) + extra_data.get("taxable_amt", 0) }) -%}

                {%- set _ = extra_data.update({'is_igst':igst_amt[0] > 0}) -%}


              </code>
