========================= #}

{% set wsp_price = frappe.db.get_value(
    "Item Price",
    {
        "item_code": item.item_code,
        "price_list": "WSP"
    },
    "price_list_rate"
) or 0 %}


{# =========================
   MRP CODE
========================= #}

{% set mrp_value = mrp_price|int|string %}

{% set mrp = namespace(code="") %}

{% for d in mrp_value %}
    {% set mrp.code = mrp.code + (mrp_map.get(d, d)) %}
{% endfor %}


{# =========================
   WSP CODE
========================= #}

{% set wsp_value = wsp_price|int|string %}

{% set wsp = namespace(code="") %}

{% for d in wsp_value %}
    {% set wsp.code = wsp.code + (wsp_map.get(d, d)) %}
{% endfor %}


