{% set hsn_digit = "" %}

{% if item.gst_hsn_code %}
    {% set hsn_digit = item.gst_hsn_code|string %}
    {% set hsn_digit = hsn_digit[0] %}
{% endif %}


<div class="secret-code">

    {{ mrp.code }}

    &nbsp;&nbsp;&nbsp;

    {{ wsp.code }}

    &nbsp;&nbsp;&nbsp;

    {{ hsn_digit }}

</div>

